import { getBlogPosts } from '@/data/blog';
import { DATA } from '@/data/resume';
import type { Metadata } from 'next';
import BlogClient from './blog-client';

export const metadata: Metadata = {
  title: 'Blog',
  description: 'My thoughts on software development, life, crypto, and more.',
  alternates: {
    canonical: `${DATA.url}/blog`
  },
  openGraph: {
    title: `Blog | ${DATA.name}`,
    description: 'My thoughts on software development, life, crypto, and more.',
    url: `${DATA.url}/blog`,
    siteName: DATA.name,
    locale: 'en_US',
    type: 'website',
    images: [
      {
        url: `${DATA.url}/og?title=${encodeURIComponent('Blog')}`,
        width: 1200,
        height: 630,
        alt: `${DATA.name} blog`
      }
    ]
  },
  twitter: {
    card: 'summary_large_image',
    title: `Blog | ${DATA.name}`,
    description: 'My thoughts on software development, life, crypto, and more.',
    creator: '@0xkkdemian',
    images: [`${DATA.url}/og?title=${encodeURIComponent('Blog')}`]
  }
};

export default async function BlogPage() {
  const posts = await getBlogPosts();
  const sortedPosts = posts.sort(
    (a, b) =>
      new Date(b.metadata.publishedAt).getTime() -
      new Date(a.metadata.publishedAt).getTime()
  );

  const blogJsonLd = {
    '@context': 'https://schema.org',
    '@type': 'Blog',
    name: `${DATA.name} Blog`,
    description: 'My thoughts on software development, life, crypto, and more.',
    url: `${DATA.url}/blog`,
    author: {
      '@type': 'Person',
      name: DATA.name,
      url: DATA.url,
    },
  };

  const itemListJsonLd = {
    '@context': 'https://schema.org',
    '@type': 'ItemList',
    name: `${DATA.name} Blog Posts`,
    description: 'Articles on Web3, DeFi, crypto investing, and blockchain technology.',
    url: `${DATA.url}/blog`,
    itemListElement: sortedPosts.map((post, index) => ({
      '@type': 'ListItem',
      position: index + 1,
      url: `${DATA.url}/blog/${post.slug}`,
      name: post.metadata.title,
    })),
  };

  return (
    <div className='mx-auto w-full max-w-4xl px-4 pb-24 pt-6 sm:px-6 sm:pb-28 sm:pt-10 lg:px-8'>
      <script
        type='application/ld+json'
        suppressHydrationWarning
        dangerouslySetInnerHTML={{ __html: JSON.stringify(blogJsonLd) }}
      />
      <script
        type='application/ld+json'
        suppressHydrationWarning
        dangerouslySetInnerHTML={{ __html: JSON.stringify(itemListJsonLd) }}
      />
      <BlogClient posts={posts} />
    </div>
  );
}

